+        fd in 0_u64..10_000,
+        ts in 0_u64..2_000_000_000,
+    ) {
+        let snap = ResourceSnapshot {
+            pid,
+            rss_bytes: rss,
+            virt_bytes: rss * 2,
+            fd_count: fd,
+            io_read_bytes: None,
+            io_write_bytes: None,
+            cpu_percent: None,
